sql:
SELECT sellers.seller_name, products.product_name 
FROM sellers 
INNER JOIN products ON sellers.seller_id = products.seller_id;

external_knowledge:
- "sailing beyond the common tide" metaphorically refers to having stock levels significantly higher than the average;
- "holding goods in stock more than twice the general sea level" means the stock quantity is more than twice the average stock quantity of all products;
- 'general sea level' refers to the average stock level of all products in the products table.

sql:
SELECT DISTINCT p.product_name 
FROM products p
JOIN orders o ON p.product_id = o.product_id;

SELECT seller_name
FROM sellers
WHERE seller_id NOT IN (SELECT seller_id FROM products);

SELECT seller_name, contact_email
FROM sellers
WHERE is_active = 1;

SELECT COUNT(*)
FROM sellers
WHERE is_active = 1;

